{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを正式にキックオフし、検討段階から実行フェーズに入ると確定した。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "毎週水曜日 10:00〜（1時間枠）に週次定例を開催し、各部署より1名ずつが必須参加でリモート参加可とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "A案およびC案ではなく、B案（段階移行）を採用し、拠点をグループに分けて順次切り替える方式とする。",
      "decided_by": "桐生 遥・全員合意"
    },
    {
      "id": "D4",
      "content": "共通基盤（認証・マスタ配信）について、サクラ商事さんへの共同利用（第3案）で進むことを確定した。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "本番リリース目標日時を当初の9月末から10月15日に変更することを確定した。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "切り替え実施タイミングを平日夜間ではなく、土曜日の深夜帯に実施することを確定した。",
      "decided_by": "全員合意"
    },
    {
      "id": "D7",
      "content": "トランザクションデータは第1フェーズで移行せず、旧システムを参照用に残す方針で進むことを確認した。",
      "decided_by": "芦田 巧・桐生 遥"
    },
    {
      "id": "D8",
      "content": "既存のロール定義を流用し新規での洗い直しは行わず、稼働後の運用改善案件として別に立てることを確定した。",
      "decided_by": "芦田 巧・桐生 遥"
    },
    {
      "id": "D9",
      "content": "現場からの障害報告の一次受け窓口を情報システム部からQAチーム（白鳥 千夏氏側）に変更することを決定した。",
      "decided_by": "白鳥 千夏提言・桐生 遥許可"
    }
  ],
